#!/usr/bin/env python3
"""check-version-drift (R12.AC6): make a CLI change tool-prompted instead of memory-dependent.

Compares the installed `claude --version` to the recorded verified version
(meta/version-data.yaml `_verified_version`, mirrored in meta/version-record.md), and — where
feasible — diffs the installed `claude --help` command list against meta/cli-commands.snapshot to
surface new / removed / renamed commands that may need coverage.

Drift is informational by default (exit 0) so it never blocks day-to-day work; pass `--strict`
(used by the scheduled refresh trigger) to exit non-zero when drift is detected. This check is
itself the worked example U16 references for "Claude in CI / on a schedule" (R14.AC2).
"""
import os
import re
import subprocess
import sys

sys.path.insert(0, os.path.dirname(os.path.abspath(__file__)))
from _common import META, Reporter, load_version_data  # noqa: E402

SNAPSHOT = META / "cli-commands.snapshot"


def installed_version():
    out = subprocess.run(["claude", "--version"], capture_output=True, text=True, timeout=30)
    m = re.search(r"\d+\.\d+\.\d+", out.stdout)
    return m.group(0) if m else None


def installed_commands():
    out = subprocess.run(["claude", "--help"], capture_output=True, text=True, timeout=30)
    cmds = set()
    in_commands = False
    for line in out.stdout.splitlines():
        if line.rstrip() == "Commands:":
            in_commands = True
            continue
        if in_commands:
            # Command rows are indented exactly two spaces; wrapped description lines are
            # indented far more, so an exact two-space anchor excludes them.
            m = re.match(r" {2}([a-z][\w|-]*)", line)
            if m:
                cmds.add(m.group(1).split("|")[0])  # "plugin|plugins" -> "plugin"
    return cmds


def main(argv):
    strict = "--strict" in argv
    rep = Reporter("check-version-drift")
    recorded = load_version_data().get("_verified_version")

    try:
        installed = installed_version()
    except (FileNotFoundError, subprocess.SubprocessError) as exc:
        rep.pending(f"could not run `claude --version` ({exc}); skipping drift check")
        return rep.done(strict=False)

    if installed is None:
        rep.pending("could not parse installed CLI version; skipping")
        return rep.done(strict=False)

    if installed == recorded:
        rep.ok(f"installed CLI {installed} matches recorded verified version")
    else:
        rep.pending(f"DRIFT: installed {installed} != recorded {recorded} — re-verify "
                    f"version-specific facts and bump meta/version-record.md (R12.AC7)")

    # command-list diff (best effort)
    if SNAPSHOT.exists():
        recorded_cmds = {c.strip() for c in SNAPSHOT.read_text().split() if c.strip()}
        try:
            now = installed_commands()
            added, removed = sorted(now - recorded_cmds), sorted(recorded_cmds - now)
            if added:
                rep.pending(f"new CLI command(s) since snapshot: {added}")
            if removed:
                rep.pending(f"CLI command(s) removed since snapshot: {removed}")
            if not added and not removed:
                rep.ok(f"command list unchanged vs snapshot ({len(now)} commands)")
        except (FileNotFoundError, subprocess.SubprocessError) as exc:
            rep.pending(f"could not diff command list ({exc})")
    else:
        rep.pending(f"no command snapshot at {SNAPSHOT.name}; run `make snapshot` to create one")

    return rep.done(strict=strict)


if __name__ == "__main__":
    raise SystemExit(main(sys.argv[1:]))

"""Shared helpers for the course's enforcement suite.

Every check imports from here so the tools stay small and consistent — they are meant to be
read verbatim as the worked examples that units U14 (hooks) and U16 (CI) reference (R14.AC2/AC3),
so clarity matters as much as correctness.

Design notes:
- The repo root is found by walking up to the directory that contains `meta/` and `course/`.
- Meaning is carried by text ("PASS"/"FAIL"/"PENDING"), never by colour alone (R15.AC6); colour
  is added only when stdout is a TTY, as decoration.
- Version-specific values live solely in meta/version-data.yaml and are referenced as {{vd:key}};
  `resolve_vd` / `render_vd` implement that single-source rule (R12.AC2).
"""
from __future__ import annotations

import os
import re
import sys
from pathlib import Path

import yaml


# --- repo layout -----------------------------------------------------------------------------

def repo_root() -> Path:
    here = Path(__file__).resolve()
    for parent in [here.parent, *here.parents]:
        if (parent / "meta").is_dir() and (parent / "course").is_dir():
            return parent
    raise SystemExit("could not locate repo root (no dir with meta/ and course/)")


ROOT = repo_root()
META = ROOT / "meta"
COURSE = ROOT / "course"
UNITS = COURSE / "units"

# Directories scanned for course artifacts (excludes the spec, tooling internals, vendored dirs).
SKIP_DIRS = {".git", ".venv", "venv", "__pycache__", "node_modules", ".pytest_cache"}


def load_yaml(path: Path):
    with open(path, "r", encoding="utf-8") as fh:
        return yaml.safe_load(fh)


def iter_markdown(*roots: Path):
    """Yield every .md file under the given roots, skipping vendored/generated dirs."""
    for root in roots:
        if not root.exists():
            continue
        for path in sorted(root.rglob("*.md")):
            if any(part in SKIP_DIRS for part in path.parts):
                continue
            yield path


def iter_text_files(*roots: Path):
    """Yield text-ish files (md/yaml/json/py/sh/toml/yml/cfg/ini) under roots."""
    exts = {".md", ".yaml", ".yml", ".json", ".py", ".sh", ".toml", ".cfg", ".ini", ".txt"}
    for root in roots:
        if not root.exists():
            continue
        for path in sorted(root.rglob("*")):
            if path.is_dir() or any(part in SKIP_DIRS for part in path.parts):
                continue
            if path.suffix in exts or os.access(path, os.X_OK):
                yield path


# --- unit front matter -----------------------------------------------------------------------

FRONTMATTER_RE = re.compile(r"^---\n(.*?)\n---\n", re.DOTALL)


def parse_frontmatter(path: Path):
    """Return the parsed YAML front-matter dict for a unit file, or None if absent."""
    text = path.read_text(encoding="utf-8")
    # Allow a leading HTML comment block (templates) before the front matter.
    text = re.sub(r"^<!--.*?-->\s*", "", text, count=1, flags=re.DOTALL)
    m = FRONTMATTER_RE.match(text)
    if not m:
        return None
    return yaml.safe_load(m.group(1))


def unit_files():
    """Authored unit files: course/units/NN-slug/unit.md (excludes templates in meta/)."""
    if not UNITS.exists():
        return []
    return sorted(UNITS.glob("*/unit.md"))


# --- version-data resolution ({{vd:key}}) ----------------------------------------------------

VD_TOKEN_RE = re.compile(r"\{\{vd:([A-Za-z0-9_-]+)\}\}")


def load_version_data():
    return load_yaml(META / "version-data.yaml")


def resolve_vd(key: str, vd: dict):
    """Resolve a single {{vd:key}}. Returns (value, unverified) or (None, None) if unknown.

    Keys starting with '_' (e.g. _verified_version) come from the file's top level; all others
    come from the `keys:` table.
    """
    if key.startswith("_"):
        val = vd.get(key)
        return (val, False) if val is not None else (None, None)
    entry = (vd.get("keys") or {}).get(key)
    if entry is None:
        return (None, None)
    return (entry.get("value", ""), bool(entry.get("unverified")))


def render_vd(text: str, vd: dict):
    """Render every {{vd:key}} in `text`. Returns (rendered_text, unresolved_keys:set).

    Unverified values are annotated inline with an explicit text marker (R12.AC3).
    """
    unresolved: set[str] = set()

    def repl(match: re.Match) -> str:
        key = match.group(1)
        value, unverified = resolve_vd(key, vd)
        if value is None:
            unresolved.add(key)
            return match.group(0)  # leave token in place; caller decides how to fail
        return f"{value} (unverified — see meta/version-record.md)" if unverified else value

    return VD_TOKEN_RE.sub(repl, text), unresolved


# --- reporting -------------------------------------------------------------------------------

_TTY = sys.stdout.isatty()


def _c(code: str, s: str) -> str:
    return f"\033[{code}m{s}\033[0m" if _TTY else s


class Reporter:
    """Tiny PASS/FAIL/PENDING reporter. `failures` drives the process exit code."""

    def __init__(self, name: str):
        self.name = name
        self.failures = 0
        self.pending_count = 0

    def ok(self, msg: str):
        print(f"  {_c('32', 'PASS')}  {msg}")

    def fail(self, msg: str):
        self.failures += 1
        print(f"  {_c('31', 'FAIL')}  {msg}")

    def pending(self, msg: str):
        self.pending_count += 1
        print(f"  {_c('33', 'PEND')}  {msg}")

    def check(self, cond: bool, ok_msg: str, fail_msg: str | None = None):
        if cond:
            self.ok(ok_msg)
        else:
            self.fail(fail_msg or ok_msg)
        return cond

    def done(self, strict: bool = False) -> int:
        """Print a summary and return an exit code. PENDING fails only under --strict."""
        bad = self.failures + (self.pending_count if strict else 0)
        tail = f" ({self.pending_count} pending)" if self.pending_count else ""
        if bad:
            print(f"{self.name}: {_c('31', 'FAILED')} — {self.failures} failure(s){tail}")
        else:
            print(f"{self.name}: {_c('32', 'OK')}{tail}")
        return 1 if bad else 0

